export default class Cursor{constructor(){this.dot=document.getElementById("cursor-dot"),this.outline=document.getElementById("cursor-outline"),this.debugPanel=document.getElementById("cursor-debug"),this.dbX=document.getElementById("db-x"),this.dbY=document.getElementById("db-y"),this.dbTarget=document.getElementById("db-target"),this.init(),this.setupDebugToggle()}setupDebugToggle(){window.addEventListener("keydown",e=>{if("`"===e.key){const e="none"===this.debugPanel.style.display;this.debugPanel.style.display=e?"block":"none"}})}init(){window.addEventListener("mousemove",e=>{const{clientX:t,clientY:n}=e;this.dot&&(this.dot.style.transform=`translate(${t}px, ${n}px)`),this.outline&&(this.outline.style.transform=`translate(${t}px, ${n}px)`),this.debugPanel&&"none"!==this.debugPanel.style.display&&(this.dbX.innerText=Math.round(t),this.dbY.innerText=Math.round(n))}),this.refresh()}refresh(){document.querySelectorAll("a, button, .project-item, .magnetic-link").forEach(e=>{e.addEventListener("mouseenter",()=>{document.body.classList.add("is-hovering"),this.dbTarget&&(this.dbTarget.innerText=e.tagName.toLowerCase()+(e.className?`.${e.className.split(" ")[0]}`:""))}),e.addEventListener("mouseleave",()=>{document.body.classList.remove("is-hovering"),e.style.transform="translate(0px, 0px)",this.dbTarget&&(this.dbTarget.innerText="None")}),e.addEventListener("mousemove",t=>{const{clientX:n,clientY:s}=t,i=e.getBoundingClientRect(),d=.3*(n-(i.left+i.width/2)),o=.3*(s-(i.top+i.height/2));e.style.transform=`translate(${d}px, ${o}px)`})})}}